/*
 * Raspberry Pi GPIO Control in C
 * Uses Linux sysfs interface (/sys/class/gpio) for GPIO access
 * Demonstrates both output (LED control) and input (button with interrupts)
 * 
 * Compile: gcc -o gpio_control gpio_control.c -lpthread
 * Run: sudo ./gpio_control
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <pthread.h>

/* GPIO pin definitions (BCM numbering) */
#define LED_PIN 18 /* GPIO pin for LED */
#define BUTTON_PIN 17 /* GPIO pin for button */
#define GPIO_MAX 64 /* Maximum GPIO value buffer */

/* File paths for sysfs GPIO interface */
#define GPIO_PATH "/sys/class/gpio/"

/* Function prototypes */
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_set_direction(int pin, const char *direction);
int gpio_set_edge(int pin, const char *edge);
int gpio_write(int pin, int value);
int gpio_read(int pin);
void *button_monitor_thread(void *arg);

/* Export GPIO pin to userspace */
int gpio_export(int pin) {
 int fd;
 char buffer[GPIO_MAX];

 fd = open("/sys/class/gpio/export", O_WRONLY);
 if (fd < 0) {
 perror("Failed to open GPIO export");
 return -1;
 }

 snprintf(buffer, GPIO_MAX, "%d", pin);
 write(fd, buffer, strlen(buffer));
 close(fd);

 printf("Exported GPIO pin %d\n", pin);
 return 0;
}

/* Unexport GPIO pin from userspace */
int gpio_unexport(int pin) {
 int fd;
 char buffer[GPIO_MAX];

 fd = open("/sys/class/gpio/unexport", O_WRONLY);
 if (fd < 0) {
 perror("Failed to open GPIO unexport");
 return -1;
 }

 snprintf(buffer, GPIO_MAX, "%d", pin);
 write(fd, buffer, strlen(buffer));
 close(fd);

 printf("Unexported GPIO pin %d\n", pin);
 return 0;
}

/* Set GPIO pin direction (in/out) */
int gpio_set_direction(int pin, const char *direction) {
 int fd;
 char path[GPIO_MAX * 2];

 snprintf(path, GPIO_MAX * 2, "%sgpio%d/direction", GPIO_PATH, pin);
 fd = open(path, O_WRONLY);
 if (fd < 0) {
 perror("Failed to set GPIO direction");
 return -1;
 }

 write(fd, direction, strlen(direction));
 close(fd);

 printf("GPIO %d set to %s\n", pin, direction);
 return 0;
}

/* Set GPIO interrupt edge (none/rising/falling/both) */
int gpio_set_edge(int pin, const char *edge) {
 int fd;
 char path[GPIO_MAX * 2];

 snprintf(path, GPIO_MAX * 2, "%sgpio%d/edge", GPIO_PATH, pin);
 fd = open(path, O_WRONLY);
 if (fd < 0) {
 perror("Failed to set GPIO edge");
 return -1;
 }

 write(fd, edge, strlen(edge));
 close(fd);

 printf("GPIO %d edge set to %s\n", pin, edge);
 return 0;
}

/* Write value to GPIO pin (0 or 1) */
int gpio_write(int pin, int value) {
 int fd;
 char path[GPIO_MAX * 2];
 char buffer[GPIO_MAX];

 snprintf(path, GPIO_MAX * 2, "%sgpio%d/value", GPIO_PATH, pin);
 fd = open(path, O_WRONLY);
 if (fd < 0) {
 perror("Failed to write GPIO value");
 return -1;
 }

 snprintf(buffer, GPIO_MAX, "%d", value);
 write(fd, buffer, 1);
 close(fd);

 return 0;
}

/* Read value from GPIO pin */
int gpio_read(int pin) {
 int fd;
 char path[GPIO_MAX * 2];
 char buffer[GPIO_MAX];

 snprintf(path, GPIO_MAX * 2, "%sgpio%d/value", GPIO_PATH, pin);
 fd = open(path, O_RDONLY);
 if (fd < 0) {
 perror("Failed to read GPIO value");
 return -1;
 }

 read(fd, buffer, GPIO_MAX);
 close(fd);

 return atoi(buffer);
}

/* Thread function to monitor button with interrupt */
void *button_monitor_thread(void *arg) {
 int button_pin = *(int *)arg;
 int fd;
 int ret;
 char path[GPIO_MAX * 2];
 char buffer[GPIO_MAX];
 fd_set rfds;
 struct timeval tv;

 printf("Button monitor thread started on GPIO %d\n", button_pin);

 /* Open value file for interrupt monitoring */
 snprintf(path, GPIO_MAX * 2, "%sgpio%d/value", GPIO_PATH, button_pin);
 fd = open(path, O_RDONLY);
 if (fd < 0) {
 perror("Failed to open button value file");
 pthread_exit(NULL);
 }

 /* Read initial value to clear interrupts */
 read(fd, buffer, GPIO_MAX);

 while (1) {
 /* Set up select() for interrupt-driven monitoring */
 FD_ZERO(&rfds);
 FD_SET(fd, &rfds);
 tv.tv_sec = 1; /* 1 second timeout */
 tv.tv_usec = 0;

 ret = select(fd + 1, &rfds, NULL, NULL, &tv);

 if (ret > 0 && FD_ISSET(fd, &rfds)) {
 /* Button state changed */
 read(fd, buffer, GPIO_MAX);
 int value = atoi(buffer);

 if (value == 1) {
 printf("BUTTON PRESSED (GPIO %d = HIGH)\n", button_pin);
 } else {
 printf("BUTTON RELEASED (GPIO %d = LOW)\n", button_pin);
 }
 }
 }

 close(fd);
 pthread_exit(NULL);
}

/* Main function demonstrating GPIO control */
int main(int argc, char *argv[]) {
 pthread_t button_thread;
 int i;

 printf("Raspberry Pi GPIO Control (C)\n");
 printf("================================\n");

 /* Export GPIO pins */
 printf("\n[1] Exporting GPIO pins...\n");
 gpio_export(LED_PIN);
 gpio_export(BUTTON_PIN);

 /* Configure LED pin as output */
 printf("\n[2] Configuring LED pin (GPIO %d)...\n", LED_PIN);
 gpio_set_direction(LED_PIN, "out");

 /* Configure Button pin as input */
 printf("\n[3] Configuring Button pin (GPIO %d)...\n", BUTTON_PIN);
 gpio_set_direction(BUTTON_PIN, "in");
 gpio_set_edge(BUTTON_PIN, "both"); /* Monitor both rising and falling */

 /* Start button monitoring thread */
 pthread_create(&button_thread, NULL, button_monitor_thread, &BUTTON_PIN);

 /* LED blink demonstration */
 printf("\n[4] LED Blink Demo - Press Ctrl+C to exit\n");
 printf("Blinking LED on GPIO %d...\n", LED_PIN);

 for (i = 0; i < 10; i++) {
 gpio_write(LED_PIN, 1); /* LED ON */
 printf("LED: ON\n");
 usleep(500000); /* 500ms */

 gpio_write(LED_PIN, 0); /* LED OFF */
 printf("LED: OFF\n");
 usleep(500000); /* 500ms */
 }

 /* Wait for button thread */
 pthread_cancel(button_thread);
 pthread_join(button_thread, NULL);

 /* Cleanup - unexport GPIO pins */
 printf("\n[5] Cleanup - Unexporting GPIO pins...\n");
 gpio_unexport(LED_PIN);
 gpio_unexport(BUTTON_PIN);

 printf("GPIO control demo complete!\n");
 return 0;
}
